package com.example.bank.service;

import com.example.bank.model.TransactionRequest;
import com.example.bank.model.TransactionResponse;

import javax.jws.WebService;

@WebService(endpointInterface = "com.example.bank.service.BankingService",
            serviceName = "BankingService",
            portName = "BankingServicePort")
public class BankingServiceImpl implements BankingService {

    @Override
    public String processTransaction(String accountId, double amount, String currency) {
        System.out.println("Server: Processing simple transaction: Account=" + accountId + ", Amount=" + amount + ", Currency=" + currency);
        // WS-Security signature verification occurs before this method is invoked.
        // If verification fails, a SOAP Fault is returned to the client.
        return "Transaction successful for account " + accountId + ". Amount: " + amount + " " + currency;
    }

    @Override
    public TransactionResponse processStructuredTransaction(TransactionRequest request) {
        System.out.println("Server: Processing structured transaction: " + request);

        // Simulate business logic based on request data
        if (request.getAmount() <= 0) {
            return new TransactionResponse(request.getTransactionId(), "FAILED", "Amount must be positive.");
        }
        if ("EUR".equals(request.getCurrency()) && request.getAmount() > 10000) {
            return new TransactionResponse(request.getTransactionId(), "PENDING", "Large EUR transaction requires manual approval.");
        }

        // If we reach this point, the message signature has been successfully verified by CXF's WS-Security interceptors.
        // We can now trust the integrity of the signed parts of the message (the SOAP Body in this configuration).

        return new TransactionResponse(request.getTransactionId(), "SUCCESS", "Transaction processed.");
    }
}

