package com.example.bank.config;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

public class PasswordCallbackHandler implements CallbackHandler {

    private Map<String, String> passwords = new HashMap<>();

    public PasswordCallbackHandler() {
        // Keystore passwords
        passwords.put("serverpass", "serverpass"); // Password for server.jks itself
        passwords.put("clientpass", "clientpass"); // Password for client.jks itself

        // Alias passwords (for private keys)
        passwords.put("clientkey", "clientpass"); // Client's private key password in client.jks
        // 'clienttrust' in server.jks refers to client's public cert, no password needed for public cert.
        // 'serverkey' would be server's private key if it were signing/encrypting, but not needed for incoming signature verification.
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String pass = passwords.get(pc.getIdentifier()); // Identifier can be alias
                if (pass == null && pc.getUsage() == WSPasswordCallback.PW_STORE) {
                    // This is for the keystore password itself, not an alias password
                    pass = passwords.get("serverpass"); // Try server keystore password
                    if(pass == null) {
                         pass = passwords.get("clientpass"); // Try client keystore password
                    }
                }

                if (pass != null) {
                    pc.setPassword(pass);
                    return;
                }
            }
        }
        throw new UnsupportedCallbackException(callbacks[0], "No password found for " + ((WSPasswordCallback) callbacks[0]).getIdentifier());
    }
}

