package com.example.bank;

import com.example.bank.config.PasswordCallbackHandler;
import com.example.bank.service.BankingServiceImpl;
import org.apache.cxf.Bus;
import org.apache.cxf.BusFactory;
import org.apache.cxf.jaxws.EndpointImpl;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.wss4j.common.ConfigurationConstants;

import javax.xml.ws.Endpoint;
import java.io.IOException;
import java.net.URL;
import java.util.HashMap;
import java.util.Map;

public class ServerRunner {

    public static void main(String[] args) {
        System.setProperty("org.apache.cxf.Logger", "org.apache.cxf.common.logging.Log4jLogger");

        System.out.println("Server: Starting Banking Service Server...");

        BankingServiceImpl implementor = new BankingServiceImpl();
        String address = "http://localhost:9000/BankingService";

        Bus bus = BusFactory.getDefaultBus();
        EndpointImpl endpoint = new EndpointImpl(bus, implementor);

        // --- WS-Security Configuration for inbound messages (Signature Verification) ---
        Map<String, Object> inProperties = new HashMap<>();

        // Action: Verify Signature
        inProperties.put(ConfigurationConstants.ACTION, ConfigurationConstants.SIGNATURE);

        // Signature properties file pointing to server.jks
        // This keystore must contain the public key of the client that signs the message.
        // "clienttrust" is the alias of the client's public key imported into server.jks.
        URL serverPropertiesURL = ServerRunner.class.getClassLoader().getResource("server_signature_properties.properties");
        if (serverPropertiesURL == null) {
            System.err.println("Server: Error: server_signature_properties.properties not found in classpath.");
            return;
        }
        inProperties.put(ConfigurationConstants.SIG_PROP_FILE, serverPropertiesURL.getFile());

        // Callback handler for keystore password
        inProperties.put(ConfigurationConstants.PW_CALLBACK_CLASS, PasswordCallbackHandler.class.getName());

        // Specifies which parts of the message are expected to be signed.
        // It's crucial for security: if the body isn't signed, it could be tampered with.
        inProperties.put(ConfigurationConstants.SIGNATURE_PARTS, "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body");

        // Optional: Ensure the signature is generated by the expected alias (clientkey from the client's perspective).
        // On the server, this refers to the alias of the client's public key certificate in the server's keystore.
        inProperties.put(ConfigurationConstants.SIG_VER_TARGET_ALIAS, "clienttrust");

        // Create the WSS4JInInterceptor and add it to the endpoint's in-interceptor chain
        WSS4JInInterceptor wssIn = new WSS4JInInterceptor(inProperties);
        endpoint.getInInterceptors().add(wssIn);

        // Publish the endpoint
        endpoint.publish(address);

        System.out.println("Server: Service published at " + address + "?wsdl");
        System.out.println("Server: Ready and waiting for signed requests...");
        System.out.println("Server: Press Enter to stop the server.");
        try {
            System.in.read();
        } catch (IOException e) {
            e.printStackTrace();
        }
        endpoint.stop();
        System.out.println("Server: Stopped.");
    }
}

