package com.example.bank;

import com.example.bank.config.PasswordCallbackHandler;
import com.example.bank.model.TransactionRequest;
import com.example.bank.model.TransactionResponse;
import com.example.bank.service.BankingService;
import org.apache.cxf.binding.soap.saaj.SAAJOutInterceptor;
import org.apache.cxf.endpoint.Client;
import org.apache.cxf.endpoint.Endpoint;
import org.apache.cxf.frontend.ClientProxy;
import org.apache.cxf.jaxws.JaxWsProxyFactoryBean;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.common.ConfigurationConstants;

import java.net.URL;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

public class ClientRunner {

    public static void main(String[] args) throws Exception {
        System.setProperty("org.apache.cxf.Logger", "org.apache.cxf.common.logging.Log4jLogger");

        System.out.println("Client: Starting Banking Service Client...");

        // Create the JAX-WS proxy factory
        JaxWsProxyFactoryBean factory = new JaxWsProxyFactoryBean();
        factory.setServiceClass(BankingService.class);
        factory.setAddress("http://localhost:9000/BankingService");

        // Create the client proxy
        BankingService clientService = (BankingService) factory.create();

        // Get the CXF client and endpoint for interceptor configuration
        Client client = ClientProxy.getClient(clientService);
        Endpoint cxfEndpoint = client.getEndpoint();

        // --- WS-Security Configuration for outbound messages (Signing) ---
        Map<String, Object> outProperties = new HashMap<>();

        // Action: Sign the message
        outProperties.put(ConfigurationConstants.ACTION, ConfigurationConstants.SIGNATURE);

        // Key identifier type (how the signature token refers to the key)
        outProperties.put(ConfigurationConstants.SIG_KEY_ID, "DirectReference");

        // Alias of the private key in client.jks to use for signing
        outProperties.put(ConfigurationConstants.USER, "clientkey");

        // Password callback handler for the private key
        outProperties.put(ConfigurationConstants.PW_CALLBACK_CLASS, PasswordCallbackHandler.class.getName());

        // Signature properties file pointing to client.jks
        URL clientPropertiesURL = ClientRunner.class.getClassLoader().getResource("client_signature_properties.properties");
        if (clientPropertiesURL == null) {
            System.err.println("Client: Error: client_signature_properties.properties not found in classpath.");
            return;
        }
        outProperties.put(ConfigurationConstants.SIG_PROP_FILE, clientPropertiesURL.getFile());

        // Parts of the message to sign (e.g., SOAP Body)
        // This must match what the server expects to be signed.
        outProperties.put(ConfigurationConstants.SIGNATURE_PARTS, "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body");

        // Create the WSS4JOutInterceptor and add it to the client's out-interceptor chain
        WSS4JOutInterceptor wssOut = new WSS4JOutInterceptor(outProperties);
        cxfEndpoint.getOutInterceptors().add(wssOut);

        // SAAJOutInterceptor is often useful with WSS4J to ensure SOAP message
        // is in a modifiable state for security headers.
        cxfEndpoint.getOutInterceptors().add(new SAAJOutInterceptor());


        System.out.println("Client: Configured with WS-Security for signing messages.");

        // --- Test calls ---
        System.out.println("\nClient: --- Calling processStructuredTransaction (USD) ---");
        TransactionRequest request = new TransactionRequest(
                UUID.randomUUID().toString(),
                "ACC12345",
                1500.75,
                "USD"
        );
        TransactionResponse response = clientService.processStructuredTransaction(request);
        System.out.println("Client: Structured Transaction Response: " + response);

        System.out.println("\nClient: --- Calling processStructuredTransaction (EUR, high value) ---");
        TransactionRequest request2 = new TransactionRequest(
                UUID.randomUUID().toString(),
                "ACC98765",
                12000.00,
                "EUR"
        );
        TransactionResponse response2 = clientService.processStructuredTransaction(request2);
        System.out.println("Client: Structured Transaction Response 2: " + response2);


        System.out.println("\nClient: --- Calling processTransaction (simple GBP) ---");
        String simpleResponse = clientService.processTransaction("ACC001", 500.00, "GBP");
        System.out.println("Client: Simple Transaction Response: " + simpleResponse);

        System.out.println("\nClient: Finished.");
    }
}

